class Solution {
public:
    int addMinimum(string word) {
        int aCount = 0, bCount = 0, cCount = 0;
        int insertions = 0;
        for (char ch : word) {
            if (ch == 'a') {
                aCount++;
            } else if (ch == 'b') {
                bCount++;
            } else {
                cCount++;
            }
        }
        insertions = min({aCount, bCount, cCount}) * 2 + abs(aCount - bCount) + abs(bCount - cCount) + abs(cCount - aCount);
        return insertions;
    }
};
```
